import React, { useState, useEffect } from 'react';
import axios from 'axios';

const BrowseBooks = () => {
  const [books, setBooks] = useState([]);
  const [search, setSearch] = useState('');
  const [filteredBooks, setFilteredBooks] = useState([]);

  useEffect(() => {
    fetchBooks();
  }, []);

  useEffect(() => {
    setFilteredBooks(
      books.filter(book =>
        book.title.toLowerCase().includes(search.toLowerCase()) ||
        book.author.toLowerCase().includes(search.toLowerCase())
      )
    );
  }, [books, search]);

  const fetchBooks = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/books');
      setBooks(res.data);
    } catch (err) {
      console.error('Error fetching books:', err);
    }
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1 style={{ color: '#4a148c', textAlign: 'center', marginBottom: '30px' }}>Browse Syllabi</h1>
      <p style={{ textAlign: 'center', color: '#6a1b9a', marginBottom: '20px' }}>
        Explore our collection of syllabi. Search by title or subject to find educational resources.
      </p>
      <div style={{ textAlign: 'center', marginBottom: '30px' }}>
        <input
          type="text"
          placeholder="Search syllabi by title or author..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{
            padding: '10px',
            width: '50%',
            borderRadius: '25px',
            border: '2px solid #ba68c8',
            fontSize: '16px',
            outline: 'none'
          }}
        />
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' }}>
        {filteredBooks.length > 0 ? (
          filteredBooks.map(book => (
            <div key={book._id} style={{
              backgroundColor: 'white',
              borderRadius: '10px',
              padding: '15px',
              boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
              border: '1px solid #e1bee7'
            }}>
              <h3 style={{ color: '#4a148c', marginBottom: '10px' }}>{book.title}</h3>
              <p style={{ color: '#7b1fa2', marginBottom: '5px' }}>Author: {book.author}</p>
              <p style={{ color: '#6a1b9a', marginBottom: '5px' }}>ISBN: {book.isbn}</p>
              <p style={{ color: '#ab47bc' }}>Available: {book.availableCopies} / {book.totalCopies}</p>
            </div>
          ))
        ) : (
          <p style={{ textAlign: 'center', color: '#6a1b9a', gridColumn: '1 / -1' }}>No books found matching your search.</p>
        )}
      </div>
    </div>
  );
};

export default BrowseBooks;
